import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const Home = () => {
  const navigate = useNavigate();

  const [vehicles, setVehicles] = useState([]);
  const [filteredVehicles, setFilteredVehicles] = useState([]);
  const [selectedType, setSelectedType] = useState("all");
  const [types, setTypes] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchVehicles = async () => {
      try {
        setLoading(true);
        const res = await axios.get("http://localhost:8070/api/vehicles");

        const available = (res.data || []).filter(
          (v) => (v.status || "").toLowerCase() === "available"
        );

        setVehicles(available);
        setFilteredVehicles(available);

        const uniqueTypes = [
          ...new Set(available.map((v) => v.type).filter(Boolean)),
        ];
        setTypes(uniqueTypes);
      } finally {
        setLoading(false);
      }
    };

    fetchVehicles();
  }, []);

  const handleFilterChange = (e) => {
    const value = e.target.value;
    setSelectedType(value);

    if (value === "all") {
      setFilteredVehicles(vehicles);
    } else {
      setFilteredVehicles(vehicles.filter((v) => v.type === value));
    }
  };

  const stats = useMemo(() => {
    const total = vehicles.length;
    const totalValue = vehicles.reduce((sum, v) => sum + Number(v.price || 0), 0);
    const avgPrice = total ? totalValue / total : 0;

    return {
      total,
      types: types.length,
      totalValue,
      avgPrice,
    };
  }, [vehicles, types]);

  const featuredVehicles = filteredVehicles.slice(0, 3);

  return (
    <div style={{ backgroundColor: "var(--bg)" }}>
      {/* HERO SECTION */}
      <div style={{
        background: "linear-gradient(135deg, var(--primary) 0%, rgba(26, 71, 42, 0.9) 100%)",
        color: "white",
        padding: "120px 20px",
        textAlign: "center",
        marginBottom: 80,
        position: "relative",
        overflow: "hidden"
      }}>
        {/* Decorative background elements */}
        <div style={{
          position: "absolute",
          top: "-50%",
          right: "-10%",
          width: "500px",
          height: "500px",
          borderRadius: "50%",
          backgroundColor: "rgba(255, 255, 255, 0.05)",
          filter: "blur(40px)"
        }} />
        <div style={{
          position: "absolute",
          bottom: "-30%",
          left: "-5%",
          width: "400px",
          height: "400px",
          borderRadius: "50%",
          backgroundColor: "rgba(255, 255, 255, 0.03)",
          filter: "blur(40px)"
        }} />

        <div style={{ maxWidth: 900, margin: "0 auto", position: "relative", zIndex: 1 }}>
          <div style={{
            fontSize: "56px",
            fontWeight: 800,
            letterSpacing: "-1px",
            marginBottom: 20,
            lineHeight: 1.2,
            textShadow: "0 2px 10px rgba(0, 0, 0, 0.2)"
          }}>
            Premium Vehicles, 
            <br />
            Extraordinary Experience
          </div>
          <div style={{
            fontSize: "18px",
            fontWeight: 300,
            opacity: 0.95,
            marginBottom: 40,
            lineHeight: 1.6,
            letterSpacing: "0.3px"
          }}>
            Discover our curated collection of luxury and premium vehicles. 
            <br />
            Professional service, competitive pricing, exceptional value.
          </div>
          <div style={{ display: "flex", gap: 16, justifyContent: "center", flexWrap: "wrap" }}>
            <button onClick={() => navigate("/vehicles")} style={{
