function VehicleCard({ vehicle: v, navigate, featured }) {
  const [selectedImageIndex, setSelectedImageIndex] = React.useState(0);
  const [imageError, setImageError] = React.useState(false);
  const [isHovered, setIsHovered] = React.useState(false);

  const imageUrl = v.images?.[selectedImageIndex]?.url || "https://via.placeholder.com/400x250?text=No+Image";

  // Auto-rotate images
  React.useEffect(() => {
    if (!v.images || v.images.length <= 1) {
      return;
    }

    const interval = setInterval(() => {
      setSelectedImageIndex(prev => (prev + 1) % v.images.length);
    }, 5000);

    return () => clearInterval(interval);
  }, [v.images]);

  return (
    <div style={{
      backgroundColor: "var(--bg-card)",
      borderRadius: "12px",
      border: "1px solid var(--border)",
      overflow: "hidden",
      transition: "all 0.4s cubic-bezier(0.4, 0, 0.2, 1)",
      cursor: "pointer",
      boxShadow: "0 4px 16px rgba(0,0,0,0.08)",
      display: "flex",
      flexDirection: "column",
      height: "100%"
    }}
    onClick={() => navigate(`/vehicles/${v._id}`)}
    onMouseEnter={(e) => {
      setIsHovered(true);
      e.currentTarget.style.transform = featured ? "translateY(-8px)" : "translateY(-6px)";
      e.currentTarget.style.boxShadow = featured ? "0 24px 48px rgba(76, 175, 80, 0.15)" : "0 16px 32px rgba(76, 175, 80, 0.12)";
      e.currentTarget.style.borderColor = "var(--primary)";
    }}
    onMouseLeave={(e) => {
      setIsHovered(false);
      e.currentTarget.style.transform = "translateY(0)";
      e.currentTarget.style.boxShadow = "0 4px 16px rgba(0,0,0,0.08)";
      e.currentTarget.style.borderColor = "var(--border)";
    }}>
      {/* Image Section */}
      <div style={{
        width: "100%",
        height: featured ? "280px" : "240px",
        overflow: "hidden",
        backgroundColor: "var(--bg-hover)",
        position: "relative",
        display: "flex",
        alignItems: "center",
        justifyContent: "center"
      }}>
        {/* Image Overlay Gradient */}
        <div style={{
          position: "absolute",
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background: isHovered ? "linear-gradient(135deg, rgba(26, 71, 42, 0.2) 0%, rgba(76, 175, 80, 0.1) 100%)" : "linear-gradient(135deg, rgba(26, 71, 42, 0.05) 0%, rgba(76, 175, 80, 0.02) 100%)",
          zIndex: 2,
          transition: "all 0.3s ease",
          pointerEvents: "none"
        }} />

        {imageError ? (
          <div style={{
            width: "100%",
            height: "100%",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            backgroundColor: "var(--bg-hover)",
            color: "var(--text-muted)",
            fontSize: "14px",
            fontWeight: 500
          }}>
            Image Not Available
          </div>
        ) : (
          <img 
            src={imageUrl}
            alt={`${v.brand} ${v.type}`}
            onError={() => setImageError(true)}
            style={{
              width: "100%",
              height: "100%",
              objectFit: "cover",
              cursor: "pointer",
              transition: "transform 0.4s cubic-bezier(0.4, 0, 0.2, 1)",
              transform: isHovered ? "scale(1.08)" : "scale(1)"
            }}
            onClick={(e) => {
              e.stopPropagation();
              navigate(`/vehicles/${v._id}`);
            }}
          />
        )}

        {/* Image Counter */}
        {v.images && v.images.length > 1 && (
          <div style={{
            position: "absolute",
            bottom: 12,
            right: 12,
            backgroundColor: "rgba(0,0,0,0.6)",
            backdropFilter: "blur(10px)",
            color: "white",
            padding: "6px 12px",
            borderRadius: "6px",
            fontSize: "11px",
            fontWeight: 700,
            zIndex: 3,
            letterSpacing: "0.3px"
          }}>
            {selectedImageIndex + 1}/{v.images.length}
          </div>
        )}

        {/* Featured Badge */}
        {featured && (
          <div style={{
            position: "absolute",
            top: 12,
            left: 12,
            backgroundColor: "var(--primary)",
            color: "white",
            padding: "6px 12px",
            borderRadius: "6px",
            fontSize: "11px",
            fontWeight: 700,
            zIndex: 3,
            letterSpacing: "0.3px",
            textTransform: "uppercase"
          }}>
            ⭐ Featured
          </div>
        )}
      </div>

      <div style={{ display: "flex", flexDirection: "column", gap: 16, height: "100%", padding: "24px", flex: 1 }}>
        {/* Header */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 12 }}>
          <div>
            <div style={{
              fontSize: "18px",
              fontWeight: 800,
              color: "var(--text)",
              letterSpacing: "-0.3px"
            }}>
              {v.brand}
            </div>
            <div style={{
              fontSize: "13px",
              color: "var(--text-muted)",
              marginTop: 4,
              fontWeight: 500,
              letterSpacing: "0.2px"
            }}>
              {v.type} • {v.year}
            </div>
          </div>
          <span style={{
            backgroundColor: "var(--primary-soft)",
            color: "var(--primary)",
            padding: "6px 12px",
            borderRadius: "6px",
            fontSize: "11px",
            fontWeight: 700,
            textTransform: "capitalize",
            whiteSpace: "nowrap",
            letterSpacing: "0.3px"
          }}>
            {v.status || "Available"}
          </span>
        </div>

        {/* Divider */}
        <div style={{ height: "1px", backgroundColor: "var(--border)" }} />

        {/* Details */}
        <div style={{ flex: 1, display: "flex", flexDirection: "column", gap: 12 }}>
          <InfoRow label="Price" value={`LKR ${Number(v.price || 0).toLocaleString()}`} />
          <InfoRow label="Vehicle No." value={v.vehicleNumber || "-"} />
          {v.details && (
            <InfoRow 
              label="Details" 
              value={v.details.length > 60 ? v.details.substring(0, 60) + "..." : v.details} 
            />
          )}
        </div>

        {/* Actions */}
        <div style={{ display: "flex", gap: 12, flexWrap: "wrap", marginTop: "auto" }}>
          <button
            onClick={(e) => {
              e.stopPropagation();
              navigate(`/vehicles/${v._id}`);
            }}
            style={{
              flex: 1,
              minWidth: 120,
              padding: "10px 16px",
              fontSize: "13px",
              fontWeight: 700,
              backgroundColor: "var(--primary)",
              color: "white",
              border: "none",
              borderRadius: "8px",
              cursor: "pointer",
              transition: "all 0.2s",
              letterSpacing: "0.3px"
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.backgroundColor = "var(--primary-hover)";
              e.currentTarget.style.transform = "translateY(-2px)";
              e.currentTarget.style.boxShadow = "0 6px 16px rgba(76, 175, 80, 0.3)";
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.backgroundColor = "var(--primary)";
              e.currentTarget.style.transform = "translateY(0)";
              e.currentTarget.style.boxShadow = "none";
            }}
          >
            View Details
          </button>
          <button
            onClick={(e) => {
              e.stopPropagation();
              navigate("/book-appointment", { state: { vehicleId: v._id } });
            }}
            style={{
              flex: 1,
              minWidth: 120,
              padding: "10px 16px",
              fontSize: "13px",
              fontWeight: 700,
              backgroundColor: "var(--bg)",
              color: "var(--text)",
              border: "1px solid var(--border)",
              borderRadius: "8px",
              cursor: "pointer",
              transition: "all 0.2s",
              letterSpacing: "0.3px"
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.borderColor = "var(--primary)";
              e.currentTarget.style.color = "var(--primary)";
              e.currentTarget.style.backgroundColor = "var(--primary-soft)";
              e.currentTarget.style.transform = "translateY(-2px)";
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.borderColor = "var(--border)";
              e.currentTarget.style.color = "var(--text)";
              e.currentTarget.style.backgroundColor = "var(--bg)";
              e.currentTarget.style.transform = "translateY(0)";
            }}
          >
            Book Drive
          </button>
        </div>
      </div>
    </div>
  );
}

